        # Set proper item delegate to fix editor sizing and handle enter key
        class FixedSizeDelegate(QtWidgets.QStyledItemDelegate):
            def __init__(self, table):
                super().__init__()
                self.table = table

            def createEditor(self, parent, option, index):
                editor = super().createEditor(parent, option, index)
                editor.setMinimumHeight(32)  # Match row height
                editor.setStyleSheet("""
                    QLineEdit {
                        font-size: 14px;
                        padding: 4px;
                        border: 1px solid #ccc;
                        border-radius: 4px;
                    }
                """)
                
                # Add validator for amount returned column (column 1)
                if index.column() == 1:  # Amount Returned column
                    editor.setValidator(QtGui.QIntValidator())
                
                # Connect enter key to move to next cell
                editor.returnPressed.connect(lambda: self.handleEnterKey(editor, index))
                return editor

            def handleEnterKey(self, editor, index):
                # Get current row and column
                row = index.row()
                col = index.column()
                
                # Move to next column in same row
                if col < self.table.columnCount() - 1:
                    next_index = self.table.model().index(row, col + 1)
                    self.table.setCurrentIndex(next_index)
                    self.table.edit(next_index)
                else:
                    # If last column, move to next row
                    next_row = row + 1
                    if next_row >= self.table.rowCount():
                        # Add new row if needed
                        self.table.insertRow(next_row)
                    next_index = self.table.model().index(next_row, 0)
                    self.table.setCurrentIndex(next_index)
                    self.table.edit(next_index)

        # Create and set the delegate
        delegate = FixedSizeDelegate(self.medicineTable)
        self.medicineTable.setItemDelegate(delegate)
        
