    def update_net_owed(self):
        """Calculate and update the net amount owed based on payment type, amount paid, and outstanding balance."""
        try:
            # Get the total amount from the amount field
            try:
                total_amount = float(self.textEdit.text() or 0)
            except ValueError:
                total_amount = 0.0
                
            # Get outstanding balance for the current provider
            provider = self.comboBox.currentText()
            outstanding_balance = get_outstanding_balance(provider) if provider != "Select a provider" else 0.0
            
            # Calculate total returned amount from medicine table
            total_returned = 0.0
            for row in range(self.medicineTable.rowCount()):
                amt = self.medicineTable.item(row, 1)
                price = self.medicineTable.item(row, 2)
                if amt and amt.text().strip() and price and price.text().strip():
                    try:
                        total_returned += float(amt.text()) * float(price.text())
                    except ValueError:
                        pass
            
            # Update the returned amount label
            self.amountReturnedLabel.setText(f"Total Returned Value: {total_returned:.2f}")
            
            # Calculate net amount before payment, including any outstanding balance
            net_amount_before_payment = (total_amount - total_returned) + outstanding_balance
            
            # Adjust based on payment type
            payment_type = ""
            payment_amount = 0.0
            
            if self.cash_radio.isChecked():
                payment_type = "cash"
                payment_amount = net_amount_before_payment
                net_owed = 0.0
            elif self.partial_radio.isChecked():
                payment_type = "partial"
                try:
                    payment_amount = float(self.payment_amount_input.text() or 0)
                    # Ensure payment amount doesn't exceed net amount
                    payment_amount = min(payment_amount, net_amount_before_payment)
                except ValueError:
                    payment_amount = 0.0
                net_owed = max(0, net_amount_before_payment - payment_amount)
            else:  # Debt
                payment_type = "debt"
                payment_amount = 0.0
                net_owed = net_amount_before_payment
            
            # Update the net owed label with color coding
            if net_owed > 0:
                self.net_owed_label.setStyleSheet("color: #d32f2f; font-weight: bold;")
            else:
                self.net_owed_label.setStyleSheet("color: #388e3c; font-weight: bold;")
                
            self.net_owed_label.setText(f"Net Owed: {net_owed:.2f}")
            
            # Update payment amount input to reflect any corrections
            if self.partial_radio.isChecked():
                self.payment_amount_input.setText(f"{payment_amount:.2f}")
            
            # Store payment info for later use
            self.payment_info = {
                'type': payment_type,
                'amount_paid': payment_amount,
                'net_owed': net_owed,
                'total_amount': total_amount,
                'total_returned': total_returned,
                'outstanding_balance_applied': min(outstanding_balance, net_amount_before_payment - (total_amount - total_returned)) if net_amount_before_payment > 0 else 0.0
            }
            
        except Exception as e:
            print(f"Error calculating net owed: {e}")
            self.net_owed_label.setText("Net Owed: Error")
            self.payment_info = {
                'type': 'error',
                'amount_paid': 0.0,
                'net_owed': 0.0
            }
    
    def get_payment_info(self):
        """Return the current payment information."""
        if not hasattr(self, 'payment_info'):
            self.update_net_owed()
        return self.payment_info
    
